package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  static class TestRecord {
    final int x;
    final String y;

    public TestRecord(int x, String y) {
      this.x = x;
      this.y = y;
    }
  }

  static class NonRecord {
    public NonRecord() {}
  }

  // Since RecordHelper is package-private or private, we create a minimal interface to mock it
  interface RecordHelper {
    <T> Constructor<T> getCanonicalRecordConstructor(Class<T> raw);
  }

  @BeforeEach
  void resetRecordHelper() throws Exception {
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~Modifier.FINAL);

    recordHelperField.set(null, null);
  }

  @SuppressWarnings("unchecked")
  @Test
  void getCanonicalRecordConstructor_returnsConstructorForRecord() throws Exception {
    // Create mock with the actual RecordHelper class loader and type to avoid ClassCastException
    Class<?> recordHelperType = Class.forName("com.google.gson.internal.reflect.ReflectionHelper$RecordHelper");
    Object mockRecordHelper = mock(recordHelperType);

    Constructor<TestRecord> constructor = TestRecord.class.getDeclaredConstructor(int.class, String.class);

    // Use reflection to stub method on mock
    recordHelperType.getMethod("getCanonicalRecordConstructor", Class.class)
        .invoke(mockRecordHelper, TestRecord.class); // just to check method presence

    // Setup stub using Mockito when/thenReturn with raw types and reflection
    when(recordHelperType.cast(mockRecordHelper))
        .thenReturn(mockRecordHelper); // dummy, not used

    // Use Mockito's doReturn for reflection-based stub
    doReturn(constructor).when(mockRecordHelper).getClass()
        .getMethod("getCanonicalRecordConstructor", Class.class)
        .invoke(mockRecordHelper, TestRecord.class);

    // Instead of above complicated approach, simpler way is to create a proxy mock with correct class loader:
    Object typedMock = mock(recordHelperType);
    // Then stub method via reflection
    recordHelperType.getMethod("getCanonicalRecordConstructor", Class.class)
        .invoke(typedMock, TestRecord.class); // just to check

    // Use Mockito's when with reflection
    when(recordHelperType.getMethod("getCanonicalRecordConstructor", Class.class).invoke(typedMock, TestRecord.class))
        .thenReturn(constructor);

    // But this is complicated, better to use this approach:

    // Cast mock to Object, then use Mockito's when on the mock with raw types:
    // So recreate mockRecordHelper as Object but cast to recordHelperType
    mockRecordHelper = mock(recordHelperType);
    // Use Mockito to stub method by using Mockito's 'when' with raw types
    when(recordHelperType.getMethod("getCanonicalRecordConstructor", Class.class).invoke(mockRecordHelper, TestRecord.class))
        .thenReturn(constructor);

    // Actually, Mockito cannot stub via reflection invoke, so better to use a dynamic proxy:
    // So final approach:

    // Create a dynamic proxy implementing recordHelperType:
    Object proxy = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperType.getClassLoader(),
        new Class<?>[]{recordHelperType},
        (proxyObj, method, args) -> {
          if ("getCanonicalRecordConstructor".equals(method.getName())
              && args.length == 1 && args[0] == TestRecord.class) {
            return constructor;
          }
          throw new UnsupportedOperationException("Unexpected method: " + method.getName());
        });

    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~Modifier.FINAL);

    recordHelperField.set(null, proxy);

    Constructor<TestRecord> result = ReflectionHelper.getCanonicalRecordConstructor(TestRecord.class);

    assertNotNull(result);
    assertEquals(constructor, result);
  }

  @Test
  void getCanonicalRecordConstructor_propagatesExceptionFromRecordHelper() throws Exception {
    Class<?> recordHelperType = Class.forName("com.google.gson.internal.reflect.ReflectionHelper$RecordHelper");

    Object proxy = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperType.getClassLoader(),
        new Class<?>[]{recordHelperType},
        (proxyObj, method, args) -> {
          if ("getCanonicalRecordConstructor".equals(method.getName())
              && args.length == 1 && args[0] == NonRecord.class) {
            throw new RuntimeException("Test exception");
          }
          throw new UnsupportedOperationException("Unexpected method: " + method.getName());
        });

    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~Modifier.FINAL);

    recordHelperField.set(null, proxy);

    RuntimeException thrown = assertThrows(RuntimeException.class, () -> {
      ReflectionHelper.getCanonicalRecordConstructor(NonRecord.class);
    });

    assertEquals("Test exception", thrown.getMessage());
  }
}
